import { fetchEventSource } from '@microsoft/fetch-event-source'

const ctrl = new AbortController()
await fetchEventSource('/api/chat', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ query, sessionCode, messages }),
  signal: ctrl.signal,
  openWhenHidden: true,
  onmessage(ev) {
    if (!ev.data) return
    const data = JSON.parse(ev.data)
    if (ev.event === 'delta') append(data.content) // 字符串累加
    if (ev.event === 'done') finish()
    if (ev.event === 'error') fail(data.message)
  },
  onerror(err) {
    throw err // 抛出可避免库默认无限重连
  },
})
// 停止：ctrl.abort()

let streamSeq = 0
async function start() {
  const seq = ++streamSeq
  await streamChat({
    onDelta(text) {
      if (seq !== streamSeq) return // 已过期
      append(text)
    },
  })
}
function stop() {
  abort.abort()
  streamSeq++
}

